use nyc_taxi_discovery;

select 
    * 
from OPENROWSET (
    BULK 'raw/vendor.csv',
    DATA_SOURCE = 'nyc_taxi_data',
    FORMAT = 'csv',
    PARSER_VERSION = '2.0',
    HEADER_ROW = true
) as vendor;

select 
    * 
from OPENROWSET (
    BULK 'raw/vendor_escaped.csv',
    DATA_SOURCE = 'nyc_taxi_data',
    FORMAT = 'csv',
    PARSER_VERSION = '2.0',
    HEADER_ROW = true,
    ESCAPECHAR = '\\'
) as vendor;

select 
    * 
from OPENROWSET (
    BULK 'raw/vendor.csv',
    DATA_SOURCE = 'nyc_taxi_data',
    FORMAT = 'csv',
    PARSER_VERSION = '2.0',
    HEADER_ROW = true,
    fieldquote = '"'
) as vendor;

use nyc_taxi_discovery;

select 
    *
from OPENROWSET (
    BULK 'raw/trip_type.tsv',
    DATA_SOURCE = 'nyc_taxi_data',
    FORMAT = 'csv',
    PARSER_VERSION = '2.0',
    HEADER_ROW = true,
    FIELDTERMINATOR = '\t'
) as trip_type;
